var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"토…. 통과했다고요?","JPN":"つ、通過しちゃったんですか？","ENG":"She... She got through?","TWN":"入……入境了？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"예. 떠난 지 얼마 안 됐습니다.","JPN":"はい、少し前に。","ENG":"Yes. It hasn't been long since she left.","TWN":"對，剛離開沒多久。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"오늘 중으로 타나베린까지 가야 한다면서, 다들 서두르는 눈치더군요.","JPN":"今日中にタナベリンまで行きたいと、皆さんお急ぎの様子でしたが。","ENG":"It seemed like everyone was in a hurry, saying they needed to get to Tanaberin by today.","TWN":"他們好像很急，說今天一定要抵達達那貝林。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요. 아무리 그래도 국경을 넘어가는데 왜 이렇게 절차가 빠른 거예요?","JPN":"ちょっと待ってください。いくらなんでも国境を超えるための手続きなのに、あまりにも早すぎませんか？","ENG":"Wait. Even so, they're crossing the border. How did they process the documents so quickly?","TWN":"可是，怎麼會這麼快就通過入境審查……？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"난민들이 통과하려면 한나절씩 걸린다고 소문이 자자한데!","JPN":"普通の難民なら通過するのに半日もかかるんですよね！","ENG":"When the refugees need the whole afternoon to get through!","TWN":"我明明聽說難民都要等很久才能通過審查！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"그, 그거야 난민들은 어떤 인간이 섞여 있을지 모르니까 그러죠.","JPN":"そ、それは難民ですとどのような人が紛れているかわかりませんから。","ENG":"W-well, that's because we don't know what kind of people are mixed among the refugees.","TWN":"那…那是因為難民中容易混雜進一些可疑人士。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"관리국 대원들 신원만 확인되면 되는데 절차가 무슨 의미입니까?","JPN":"管理局の隊員は、本人確認さえ取れればいいわけですし、手続きは事実上ないも同然ですよ。","ENG":"What's the point of checking the documents when we can just check the Administration members' IDs?","TWN":"而且既然都已經確定是管理局的人，哪還有需要做什麼審查。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으으……!","JPN":"うう……！","ENG":"Urgh...!","TWN":"呃呃……！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어떻게 됐어? 아주머니는 찾았어?","JPN":"……どうなったの？　おばさんは見つかった？","ENG":"What happened? Did you find Madam Schneider?","TWN":"怎麼樣？有找到伯母嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 벌써 지나가 버렸대요.","JPN":"いいえ。すでに通過してしまったみたいです。","ENG":"Nope. She already went through.","TWN":"沒有，他們已經入境了……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"진짜? 그, 그럼 이제 어떡해?","JPN":"ええ？　じゃ、じゃあどうしたらいいの？","ENG":"Really? W-what do we do now?","TWN":"真的假的？那現在要怎麼辦？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어떻게든 따라잡아야죠.","JPN":"なんとしてでも追いつくしかありません。","ENG":"We have to catch up to her.","TWN":"想辦法追上他們囉。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"길은 알고 있습니까?","JPN":"道は知っているんですか？","ENG":"Do you know the way?","TWN":"你知道路嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"오늘 중으로 타나베린까지 가려면…. 50호선 고속도로 말고는 다른 길이 없어요.","JPN":"今日中にタナベリンまで着こうと思ったら……50号線高速道路を使う方法以外はありません。","ENG":"To reach Tanaberin by today... I-50 is our only option.","TWN":"要想在今天之內抵達達那貝林，就只能走50號線高速公路。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어쩔 수 없어, 호라이즌! 변신하자!","JPN":"仕方ないわね、ホライズン！　変身して！","ENG":"We have no other choice, Horizon! Let's transform!","TWN":"沒辦法了，地平線！變身吧！"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼은 제가 대중교통으로 보입니까? 수정체에 문제가 있는지 검진할 필요가 있군요.","JPN":"レイチェルは私が交通機関か何かだと思っているんですか？　水晶体に問題がないか検診することをお勧めします。","ENG":"Do I look like public transportation to you, Rachel? I suggest you get your retina examined.","TWN":"瑞秋，你當我是交通工具嗎？看來有必要檢查一下你的水晶體是否出問題。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};